using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests;

internal static class TestHelpers
{
    public static SchoolContext CreateContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    public static SchoolContext CreateSeededContext(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var context = CreateContext(dbName);
        SeedBasicData(context);
        return context;
    }

    public static void SeedBasicData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor1.ID
        };
        var dept2 = new Department
        {
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor2.ID
        };
        context.Departments.AddRange(dept, dept2);
        context.SaveChanges();

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };
        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = dept2.DepartmentID,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        // Create course assignments
        context.CourseAssignments.Add(new CourseAssignment
        {
            CourseID = course1.CourseID,
            InstructorID = instructor1.ID
        });
        context.CourseAssignments.Add(new CourseAssignment
        {
            CourseID = course2.CourseID,
            InstructorID = instructor2.ID
        });
        context.SaveChanges();

        var student1 = new Student
        {
            FirstMidName = "Alice",
            LastName = "Smith",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };
        var student2 = new Student
        {
            FirstMidName = "Bob",
            LastName = "Jones",
            EnrollmentDate = DateTime.Parse("2021-01-15")
        };
        var student3 = new Student
        {
            FirstMidName = "Charlie",
            LastName = "Brown",
            EnrollmentDate = DateTime.Parse("2019-09-01")
        };
        context.Students.AddRange(student1, student2, student3);
        context.SaveChanges();

        // Add an enrollment
        context.Enrollments.Add(new Enrollment
        {
            StudentID = student1.ID,
            CourseID = course1.CourseID,
            Grade = Grade.A
        });
        context.SaveChanges();
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    [TestCleanup]
    public void Cleanup()
    {
        TestHelpers.DrainNotificationQueue();
    }

    [TestMethod]
    public void SendNotification_Create_WithDisplayName_GeneratesCorrectMessage()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Student", "1", "Alice Smith", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'Alice Smith' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_Create_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Student", "42", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        // Assert
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_Update_GeneratesCorrectMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_Delete_GeneratesCorrectMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_SetsEntityType()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
    }

    [TestMethod]
    public void SendNotification_SetsEntityId()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "42", "Alice", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("42", notification.EntityId);
    }

    [TestMethod]
    public void SendNotification_SetsOperationString()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Alice", EntityOperation.UPDATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Alice", EntityOperation.CREATE, null);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Alice", EntityOperation.CREATE, "admin");
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToNow()
    {
        using var sut = new NotificationService();
        var before = DateTime.Now;

        sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var after = DateTime.Now;
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before.AddSeconds(-1) && notification.CreatedAt <= after.AddSeconds(1));
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        using var sut = new NotificationService();

        var result = sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_DequeuesInFifoOrder()
    {
        using var sut = new NotificationService();
        sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);

        var first = sut.ReceiveNotification();
        var second = sut.ReceiveNotification();

        Assert.AreEqual("1", first.EntityId);
        Assert.AreEqual("2", second.EntityId);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        using var sut = new NotificationService();

        // MarkAsRead is a no-op for in-memory but should not throw
        sut.MarkAsRead(1);
        sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var sut = new NotificationService();
        sut.Dispose();
        // No exception expected
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "42", "   ", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "42", "", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "42", null, EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_SetsOperationStringCREATE()
    {
        using var sut = new NotificationService();

        sut.SendNotification("X", "1", EntityOperation.CREATE);
        var notification = sut.ReceiveNotification();

        Assert.AreEqual("CREATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_SetsOperationStringDELETE()
    {
        using var sut = new NotificationService();

        sut.SendNotification("X", "1", EntityOperation.DELETE);
        var notification = sut.ReceiveNotification();

        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_SetsFieldsCorrectly()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Instructor", "7", EntityOperation.UPDATE);
        var notification = sut.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("7", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("Instructor (ID: 7) has been updated", notification.Message);
        Assert.AreEqual("System", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var items = new List<string> { "a", "b" };

        var sut = new PaginatedList<string>(items, 10, 2, 3);

        Assert.AreEqual(2, sut.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages_RoundsUp()
    {
        var items = new List<string> { "a" };

        var sut = new PaginatedList<string>(items, 10, 1, 3);

        // ceil(10/3) = 4
        Assert.AreEqual(4, sut.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsAllItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var sut = new PaginatedList<string>(items, 10, 1, 5);

        Assert.AreEqual(3, sut.Count);
        Assert.AreEqual("a", sut[0]);
        Assert.AreEqual("b", sut[1]);
        Assert.AreEqual("c", sut[2]);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var sut = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        Assert.IsFalse(sut.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var sut = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        Assert.IsTrue(sut.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ThirdPage_ReturnsTrue()
    {
        var sut = new PaginatedList<string>(new List<string>(), 20, 3, 5);

        Assert.IsTrue(sut.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // 10 items, 5 per page = 2 total pages, on page 2
        var sut = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        Assert.IsFalse(sut.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, 5 per page = 2 total pages, on page 1
        var sut = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        Assert.IsTrue(sut.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // 3 items, 5 per page = 1 total page
        var sut = new PaginatedList<string>(new List<string>(), 3, 1, 5);

        Assert.IsFalse(sut.HasNextPage);
    }

    [TestMethod]
    public void TotalPages_ExactDivision_NoExtraPage()
    {
        var sut = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.AreEqual(2, sut.TotalPages);
    }

    [TestMethod]
    public void TotalPages_SingleItem_SinglePage()
    {
        var sut = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);

        Assert.AreEqual(1, sut.TotalPages);
    }

    [TestMethod]
    public void TotalPages_ZeroCount_ZeroPages()
    {
        var sut = new PaginatedList<int>(new List<int>(), 0, 1, 10);

        Assert.AreEqual(0, sut.TotalPages);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages); // ceil(25/10) = 3
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]); // First item on page 2
        Assert.AreEqual(20, result[9]); // Last item on page 2
    }

    [TestMethod]
    public void Create_FirstPage_ContainsFirstItems()
    {
        var source = Enumerable.Range(1, 15).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ContainsRemainingItems()
    {
        var source = Enumerable.Range(1, 12).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages); // ceil(12/5) = 3
        Assert.AreEqual(2, result.Count); // Only 2 items remain
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }

    [TestMethod]
    public void Create_SingleItemSource_ReturnsOneItem()
    {
        var source = new[] { 42 }.AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(1, result.Count);
        Assert.AreEqual(42, result[0]);
    }
}

