using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private string _dbName;
    private SchoolContext _context;
    private StudentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _dbName = Guid.NewGuid().ToString();

        // Seed with a temporary context
        using (var seedContext = TestHelpers.CreateContext(_dbName))
        {
            seedContext.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Smith", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Bob", LastName = "Jones", EnrollmentDate = DateTime.Parse("2021-01-15") },
                new Student { FirstMidName = "Charlie", LastName = "Brown", EnrollmentDate = DateTime.Parse("2019-09-01") }
            );
            seedContext.SaveChanges();
        }

        // Controller gets a fresh context
        _context = TestHelpers.CreateContext(_dbName);
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    // --- Index: Sorting ---

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        Assert.AreEqual("Brown", model[0].LastName);
        Assert.AreEqual("Jones", model[1].LastName);
        Assert.AreEqual("Smith", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Smith", model[0].LastName);
        Assert.AreEqual("Jones", model[1].LastName);
        Assert.AreEqual("Brown", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Brown", model[0].LastName);  // 2019
        Assert.AreEqual("Smith", model[1].LastName);   // 2020
        Assert.AreEqual("Jones", model[2].LastName);   // 2021
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Jones", model[0].LastName);   // 2021
        Assert.AreEqual("Smith", model[1].LastName);   // 2020
        Assert.AreEqual("Brown", model[2].LastName);   // 2019
    }

    // --- Index: ViewBag sort parameters ---

    [TestMethod]
    public void Index_DefaultSort_SetsNameSortParmToNameDesc()
    {
        _controller.Index(null, null, null, null);

        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_DefaultSort_SetsDateSortParmToDate()
    {
        _controller.Index(null, null, null, null);

        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_NameDescSort_SetsNameSortParmToEmpty()
    {
