        Assert.IsNotNull(model);
        Assert.AreEqual(studentId, model.ID);
    }

    // --- Create GET ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentDefaultDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST ---

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Diana",
            LastName = "Prince",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SavesStudentToDatabase()
    {
        var student = new Student
        {
            FirstMidName = "Diana",
            LastName = "Prince",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        _controller.Create(student);

        Assert.AreEqual(4, _context.Students.Count()); // 3 seeded + 1 new
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Diana",
            LastName = "Prince",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DefaultDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Diana",
            LastName = "Prince",
            EnrollmentDate = default(DateTime)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Diana",
            LastName = "Prince",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Diana",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
    }

    // --- Edit GET ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.AsNoTracking().First().ID;

        var result = _controller.Edit((int?)studentId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(studentId, model.ID);
    }

    // --- Edit POST ---

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var existingId = _context.Students.AsNoTracking().First().ID;
        var editedStudent = new Student
        {
            ID = existingId,
