        };

        var result = _controller.Edit(editedStudent) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Alice",
            LastName = "Smith",
