    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual(400, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NonexistentId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        var studentId = _context.Students.AsNoTracking().First().ID;

        var result = _controller.Delete(studentId) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(studentId, model.ID);
    }

    // --- DeleteConfirmed POST ---

    [TestMethod]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
