namespace ContosoUniversity.Tests;

[TestClass]
public sealed class CoursesControllerTests
{
    private string _dbName;
    private SchoolContext _context;
    private CoursesController _controller;
    private Mock<IWebHostEnvironment> _mockEnv;
    private Mock<ILogger<CoursesController>> _mockLogger;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _dbName = Guid.NewGuid().ToString();

        using (var seedContext = TestHelpers.CreateContext(_dbName))
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            seedContext.Departments.Add(dept);
            seedContext.SaveChanges();

            seedContext.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
            );
            seedContext.SaveChanges();
        }

        _context = TestHelpers.CreateContext(_dbName);
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewWithAllCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
