    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _dbName = Guid.NewGuid().ToString();

        using (var seedContext = TestHelpers.CreateContext(_dbName))
        {
            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>()
            };
            seedContext.Instructors.AddRange(instructor1, instructor2);
            seedContext.SaveChanges();

            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor1.ID
            };
            seedContext.Departments.Add(dept);
            seedContext.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            seedContext.Courses.AddRange(course1, course2);
            seedContext.SaveChanges();

            seedContext.CourseAssignments.Add(new CourseAssignment
            {
                CourseID = course1.CourseID,
                InstructorID = instructor1.ID
            });
            seedContext.SaveChanges();

            // Add a student and enrollment for courseID filtering test
            var student = new Student
            {
                FirstMidName = "Alice",
                LastName = "Smith",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };
            seedContext.Students.Add(student);
            seedContext.SaveChanges();

            seedContext.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = course1.CourseID,
                Grade = Grade.A
