            .First(i => i.LastName == "Abercrombie").ID;
        var deptId = _context.Departments.AsNoTracking()
            .First(d => d.InstructorID == instructorId).DepartmentID;

        _controller.DeleteConfirmed(instructorId);

        var dept = _context.Departments.Find(deptId);
        Assert.IsNull(dept.InstructorID);
    }
}

