using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new NotificationsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
        TestHelpers.DrainNotificationQueue();
    }

    // --- GetNotifications ---

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        // Use dynamic to access anonymous type properties
        var json = System.Text.Json.JsonSerializer.Serialize(value);
        var doc = System.Text.Json.JsonDocument.Parse(json);
        Assert.IsTrue(doc.RootElement.GetProperty("success").GetBoolean());
        Assert.AreEqual(0, doc.RootElement.GetProperty("count").GetInt32());
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - enqueue some notifications
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        var doc = System.Text.Json.JsonDocument.Parse(json);
        Assert.IsTrue(doc.RootElement.GetProperty("success").GetBoolean());
        Assert.AreEqual(2, doc.RootElement.GetProperty("count").GetInt32());
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - enqueue 15 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        var doc = System.Text.Json.JsonDocument.Parse(json);
        Assert.AreEqual(10, doc.RootElement.GetProperty("count").GetInt32());
    }

    [TestMethod]
    public void GetNotifications_DrainsQueueUpToLimit()
    {
        // Arrange
        var service = new NotificationService();
        service.SendNotification("Student", "1", EntityOperation.CREATE);
        service.SendNotification("Student", "2", EntityOperation.CREATE);
        service.SendNotification("Student", "3", EntityOperation.CREATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert - all 3 should be returned
        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        var doc = System.Text.Json.JsonDocument.Parse(json);
        Assert.AreEqual(3, doc.RootElement.GetProperty("count").GetInt32());

        // Queue should now be empty
        var remainingResult = _controller.GetNotifications();
        var remainingJson = System.Text.Json.JsonSerializer.Serialize(remainingResult.Value);
        var remainingDoc = System.Text.Json.JsonDocument.Parse(remainingJson);
        Assert.AreEqual(0, remainingDoc.RootElement.GetProperty("count").GetInt32());
    }

    // --- MarkAsRead ---

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        var doc = System.Text.Json.JsonDocument.Parse(json);
        Assert.IsTrue(doc.RootElement.GetProperty("success").GetBoolean());
    }

    [TestMethod]
    public void MarkAsRead_NonexistentId_StillReturnsSuccess()
    {
        // MarkAsRead is a no-op in the in-memory implementation
        var result = _controller.MarkAsRead(99999);

        var json = System.Text.Json.JsonSerializer.Serialize(result.Value);
        var doc = System.Text.Json.JsonDocument.Parse(json);
        Assert.IsTrue(doc.RootElement.GetProperty("success").GetBoolean());
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
    }
}

